const https = require("https");
const http  = require("http");
const fs    = require("fs");
const path  = require("path");
const url   = require("url");

const PORT       = process.env.PORT || 3000;
const OPENAI_KEY = process.env.OPENAI_API_KEY || "";
const IMG_B64    = "";

function buildPrompt(ev) {
  var name    = (ev.name    || "").trim();
  var prefix  = (ev.prefix  || "").trim();
  var genre   = (ev.genre   || "HALLOWEEN EDITION").trim();
  var day     = (ev.day     || "SAMSTAG").trim();
  var date    = (ev.date    || "").trim();
  var dj      = (ev.dj      || "").trim();
  var contact = (ev.contact || "").trim();
  var time    = (ev.time    || "").trim();
  var entry   = (ev.entry   || "").trim();

  // Build DJ list
  var djList = dj.length ? dj.split(",").map(function(d){return d.trim();}).filter(Boolean) : [];
  var djSection = djList.length
    ? "DJ/ACTS section (show ONLY these names, no others):\n" + djList.map(function(d,i){return "  Line "+(i+1)+": "+d;}).join("\n")
    : "DJ/ACTS section: remove all DJ and act names completely";

  var p = "";
  p += "Edit this flyer. Keep ALL visuals identical (pumpkin figure, green-eye woman, red silhouette, blood effects, green logo, textures).\n\n";
  p += "Replace ALL text with ONLY these values:\n\n";
  p += (prefix ? "ABOVE TITLE: \"" + prefix + "\"\n" : "ABOVE TITLE: remove completely (no '3 Jahre' or any text here)\n");
  p += "MAIN TITLE: \"" + name + "\"\n";
  p += "RED BANNER: \"" + genre + "\"\n";
  p += "DATE LINE 1: \"" + day + "\"\n";
  p += "DATE LINE 2: \"" + date + "\"\n";
  p += djSection + "\n";
  p += "WEBSITE: \"" + contact + "\"\n";
  if (time)  p += "EINLASS: \"Einlass: " + time + " Uhr\"\n";
  if (entry) p += "EINTRITT: \"Eintritt: " + entry + "\"\n";
  p += "\nIMPORTANT: Do not add any text that is not listed above. Do not keep any original text that is not in this list.";
  return p;
}

function generate(ev, cb) {
  var prompt = buildPrompt(ev);
  console.log("PROMPT:\n" + prompt);

  var payload = JSON.stringify({
    model: "gpt-4o",
    input: [{
      role: "user",
      content: [
        { type: "input_image", image_url: "data:image/jpeg;base64," + IMG_B64 },
        { type: "input_text",  text: prompt }
      ]
    }],
    tools: [{ type: "image_generation", quality: "high", size: "1024x1536" }]
  });

  var req = https.request({
    hostname: "api.openai.com",
    path: "/v1/responses",
    method: "POST",
    headers: {
      "Authorization":  "Bearer " + OPENAI_KEY,
      "Content-Type":   "application/json",
      "Content-Length": Buffer.byteLength(payload)
    }
  }, function(res) {
    var data = "";
    res.on("data", function(c){ data += c; });
    res.on("end", function() {
      console.log("Status:", res.statusCode, data.substring(0,300));
      try {
        var j = JSON.parse(data);
        if (res.statusCode !== 200) return cb(new Error(j.error && j.error.message || data.substring(0,300)));
        var imgB64 = null;
        (j.output || []).forEach(function(item) {
          if (item.type === "image_generation_call") imgB64 = item.result;
          (item.content || []).forEach(function(c) {
            if (c.type === "image_generation_call") imgB64 = c.result;
          });
        });
        if (!imgB64) return cb(new Error("No image in response: " + data.substring(0,300)));
        cb(null, "data:image/png;base64," + imgB64);
      } catch(e) { cb(new Error("Parse error: " + data.substring(0,200))); }
    });
  });
  req.on("error", cb);
  req.write(payload);
  req.end();
}

var server = http.createServer(function(req, res) {
  var p = url.parse(req.url).pathname;
  res.setHeader("Access-Control-Allow-Origin","*");
  res.setHeader("Access-Control-Allow-Headers","Content-Type");
  if (req.method === "OPTIONS") { res.writeHead(200); res.end(); return; }

  if (req.method === "GET" && p === "/") {
    fs.readFile(path.join(__dirname,"public","index.html"), function(err, data) {
      if (err) { res.writeHead(404); res.end("Not found"); return; }
      res.setHeader("Content-Type","text/html");
      res.writeHead(200); res.end(data);
    });
    return;
  }

  if (req.method === "POST" && p === "/api/generate") {
    if (!OPENAI_KEY) { res.writeHead(500); res.end(JSON.stringify({error:"OPENAI_API_KEY not set"})); return; }
    var body = "";
    req.on("data", function(c){ body += c; });
    req.on("end", function() {
      var ev;
      try { ev = JSON.parse(body); } catch(e) { res.writeHead(400); res.end(JSON.stringify({error:"Invalid JSON"})); return; }
      generate(ev, function(err, src) {
        if (err) { res.writeHead(500); res.end(JSON.stringify({error: err.message})); return; }
        res.setHeader("Content-Type","application/json");
        res.writeHead(200);
        res.end(JSON.stringify({url: src}));
      });
    });
    return;
  }
  res.writeHead(404); res.end("Not found");
});
server.timeout = 240000;
server.listen(PORT, function(){ console.log("NightKit on port " + PORT); });
